    let fileInfo = try await System.shared.runAndCollectOutput(
        [
            "file",
            appClipPath.appending(component: appClip).pathString,
        ]
    )
    #expect(
        fileInfo.standardOutput.contains(architecture),
        sourceLocation: sourceLocation
    )
}

