}

private static func runCommand(
    _ command: (some ParsableCommand).Type,
    _ arguments: [String] = [],
    options: Set<TuistTestRunOption> = Set()
) async throws {
    let run = {
        var parsedCommand = try command.parseAsRoot(arguments)
        if var asyncCommand = parsedCommand as? AsyncParsableCommand {
            try await asyncCommand.run()
        } else {
            try parsedCommand.run()
        }
    }
    // ... simulator lock handling
}
```

### 4. Acceptance Tests Pattern - Explicit `--path` Arguments Required

**Location:** `/Users/pepicrft/src/github.com/tuist/tuist3/cli/Tests/TuistGeneratorAcceptanceTests/GenerateAcceptanceTests.swift`

The acceptance tests **do NOT** get the path from the environment. Instead, they:
- Retrieve the fixture directory via `TuistTest.fixtureDirectory` task local
- **Explicitly pass `--path` argument** to commands
- Helper functions build the full argument list

**Example from the `focused_targets()` test (lines 77-101):**
```swift
