    }

    try await run(GenerateCommand.self)  // Helper adds --path and --no-open
    // ... assertions
    try await run(GenerateCommand.self, "AppCore")  // Adds arguments
}
```

The `run()` helper function (lines 1512-1522) constructs the full command:
```swift
private func run(
    _: GenerateCommand.Type,
    _ arguments: [String] = [],
    sourceLocation: SourceLocation = #_sourceLocation
) async throws {
    let fixturePath = try fixtureDirectory(sourceLocation: sourceLocation)
    try await TuistTest.run(
        GenerateCommand.self,
        ["--no-open", "--path", fixturePath.pathString] + arguments
    )
}
```

